            var end = makeNode(3, 0);
            var meetFromEnd = makeNode(2, 0, end);

            PF.Util.biBacktrace(meetFromStart, meetFromEnd).should.eql([
                [0, 0],
                [1, 0],
                [2, 0],
                [3, 0]
            ]);
        });
    });

    describe('pathLength', function() {
        it('should compute euclidean length across all segments', function() {
            var path = [
                [0, 0],
                [3, 4],
                [6, 8]
            ];

