                [0, 1, 0],
                [0, 0, 0],
                [0, 0, 0]
            ]);
            var path = [
                [0, 0],
                [0, 1],
                [1, 1],
                [2, 1],
                [2, 0]
            ];

            PF.Util.smoothenPath(grid, path).should.eql([
                [0, 0],
                [1, 1],
                [2, 0]
            ]);
        });

        it('should return a single-point path unchanged', function() {
            var grid = new PF.Grid(3, 3);
